import "./toggle.css";

import { Toggle } from "radix-ui";
import { cn } from "tailwind-variants";

import { toggleVariants, type ToggleVariants } from "./toggle.variants";

export type ToggleProps = React.ComponentProps<typeof Toggle.Root> & ToggleVariants;

export const ToggleRoot = ({ className, size, variant, ...props }: ToggleProps) => {
  const { root } = toggleVariants({ size, variant });

  return <Toggle.Root className={cn(root(), className)} {...props} />;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const toggleVariants = tv({
  slots: {
    root: "toggle",
  },
  variants: {
    variant: {
      default: { root: "toggle--default" },
      outline: { root: "toggle--outline" },
    },
    size: {
      sm: { root: "toggle--sm" },
      md: { root: "toggle--md" },
      lg: { root: "toggle--lg" },
    },
  },
  defaultVariants: {
    variant: "default",
    size: "md",
  },
});

export type ToggleVariants = VariantProps<typeof toggleVariants>;

.toggle {
  @apply inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors;

  &:hover {
    @apply bg-muted text-muted-foreground;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply pointer-events-none opacity-50;
  }

  &[data-state="on"] {
    @apply bg-accent text-accent-foreground;
  }
}

.toggle--default {
  @apply bg-transparent;
}

.toggle--outline {
  @apply border-input border bg-transparent;

  &:hover {
    @apply bg-accent text-accent-foreground;
  }
}

.toggle--sm {
  @apply size-8;
}

.toggle--md {
  @apply size-9;
}

.toggle--lg {
  @apply size-10;
}

import { ToggleRoot } from "./toggle";

export const Toggle = {
  Root: ToggleRoot,
};

export { ToggleRoot };

export { type ToggleVariants, toggleVariants } from "./toggle.variants";
